+
+    <div id="summary" class="summary" style="display: none;">
+        <h2>📊 Test Summary</h2>
+        <div class="summary-grid">
+            <div class="summary-item">
+                <div class="label">Total Tests</div>
+                <div class="value" id="total-tests">0</div>
+            </div>
+            <div class="summary-item">
+                <div class="label">Passed</div>
+                <div class="value" id="passed-tests" style="color: #22c55e;">0</div>
+            </div>
+            <div class="summary-item">
+                <div class="label">Failed</div>
+                <div class="value" id="failed-tests" style="color: #ef4444;">0</div>
+            </div>
+            <div class="summary-item">
+                <div class="label">Total Time</div>
+                <div class="value" id="total-time">0ms</div>
+            </div>
+        </div>
+    </div>
+
+    <script type="module">
+        import { vault } from './lanceql.js';
+
+        let v = null;
+        let testResults = { total: 0, passed: 0, failed: 0, time: 0 };
+
+        function setStatus(id, type, message) {
+            const el = document.getElementById(`status-${id}`);
+            el.className = `status ${type}`;
+            el.innerHTML = message;
+        }
+
+        function enableButton(id) {
+            document.getElementById(`btn-${id}`).disabled = false;
+        }
+
+        async function runTest(sql, validate = null) {
+            const start = performance.now();
+            try {
+                const result = await v.exec(sql);
+                const time = performance.now() - start;
+                testResults.time += time;
+
+                if (validate) {
+                    const valid = validate(result);
+                    if (!valid.pass) {
+                        return { pass: false, time, error: valid.reason, result };
+                    }
+                }
+                return { pass: true, time, result };
+            } catch (e) {
+                return { pass: false, time: performance.now() - start, error: e.message };
+            }
+        }
+
+        function renderResults(tests) {
+            let html = '<table><tr><th>SQL</th><th>Result</th><th>Time</th><th>Details</th></tr>';
+            let allPassed = true;
+
+            for (const t of tests) {
+                testResults.total++;
+                if (t.pass) {
+                    testResults.passed++;
+                    html += `<tr>
+                        <td><code class="sql-code">${escapeHtml(t.sql)}</code></td>
+                        <td class="pass">✓ PASS</td>
+                        <td>${t.time.toFixed(2)}ms</td>
+                        <td>${t.details || ''}</td>
+                    </tr>`;
+                } else {
+                    testResults.failed++;
+                    allPassed = false;
+                    html += `<tr>
+                        <td><code class="sql-code">${escapeHtml(t.sql)}</code></td>
+                        <td class="fail">✗ FAIL</td>
+                        <td>${t.time.toFixed(2)}ms</td>
+                        <td>${escapeHtml(t.error || '')}</td>
+                    </tr>`;
+                }
+            }
+            html += '</table>';
+            return { html, allPassed };
+        }
+
+        function escapeHtml(str) {
+            if (!str) return '';
+            return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
+        }
+
+        function updateSummary() {
+            document.getElementById('summary').style.display = 'block';
+            document.getElementById('total-tests').textContent = testResults.total;
+            document.getElementById('passed-tests').textContent = testResults.passed;
+            document.getElementById('failed-tests').textContent = testResults.failed;
+            document.getElementById('total-time').textContent = testResults.time.toFixed(0) + 'ms';
+        }
+
+        // =========================================================================
+        // Test Functions
+        // =========================================================================
+
+        window.testInit = async function() {
+            setStatus('init', 'loading', '⏳ Initializing vault...');
+            try {
+                v = await vault();
+                setStatus('init', 'success', '✓ Vault initialized successfully');
+                enableButton('create');
+            } catch (e) {
+                setStatus('init', 'error', `✗ Failed: ${e.message}`);
+            }
+        };
+
+        window.testCreate = async function() {
+            setStatus('create', 'loading', '⏳ Running CREATE TABLE tests...');
+            const tests = [];
+
+            // Test 1: Basic CREATE TABLE
+            let r = await runTest("CREATE TABLE users (id INT, name TEXT, age INT)");
+            tests.push({ sql: "CREATE TABLE users (id INT, name TEXT, age INT)", ...r });
+
+            // Test 2: CREATE TABLE IF NOT EXISTS (should not error)
+            r = await runTest("CREATE TABLE IF NOT EXISTS users (id INT, name TEXT)");
+            tests.push({ sql: "CREATE TABLE IF NOT EXISTS users (id INT)", ...r });
+
+            // Test 3: Create another table
+            r = await runTest("CREATE TABLE products (id INT, name TEXT, price FLOAT)");
+            tests.push({ sql: "CREATE TABLE products (id INT, name TEXT, price FLOAT)", ...r });
+
+            // Test 4: Create orders table for JOIN tests
+            r = await runTest("CREATE TABLE orders (id INT, user_id INT, product TEXT, amount INT)");
+            tests.push({ sql: "CREATE TABLE orders (...)", ...r });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-create').innerHTML = html;
+            setStatus('create', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} CREATE tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('insert');
+            updateSummary();
+        };
+
+        window.testInsert = async function() {
+            setStatus('insert', 'loading', '⏳ Running INSERT tests...');
+            const tests = [];
+
+            // Single row insert
+            let r = await runTest("INSERT INTO users (id, name, age) VALUES (1, 'Alice', 30)");
+            tests.push({ sql: "INSERT INTO users VALUES (1, 'Alice', 30)", ...r });
+
+            // Multiple row insert
+            r = await runTest("INSERT INTO users VALUES (2, 'Bob', 25), (3, 'Charlie', 35), (4, 'Diana', 28)");
+            tests.push({ sql: "INSERT INTO users VALUES (2, 'Bob', 25), (3, ...), (4, ...)", ...r });
+
+            // More users for testing
+            r = await runTest("INSERT INTO users VALUES (5, 'Eve', 30), (6, 'Frank', 45)");
+            tests.push({ sql: "INSERT INTO users VALUES (5, 'Eve', 30), (6, 'Frank', 45)", ...r });
+
+            // Insert into products
+            r = await runTest("INSERT INTO products VALUES (1, 'Laptop', 999.99), (2, 'Phone', 599.50), (3, 'Tablet', 399.00)");
+            tests.push({ sql: "INSERT INTO products VALUES (...)", ...r });
+
+            // Insert into orders for JOIN tests
+            r = await runTest("INSERT INTO orders VALUES (1, 1, 'Laptop', 1), (2, 2, 'Phone', 2), (3, 1, 'Tablet', 1)");
+            tests.push({ sql: "INSERT INTO orders VALUES (...)", ...r });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-insert').innerHTML = html;
+            setStatus('insert', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} INSERT tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('select-basic');
+            updateSummary();
+        };
+
+        window.testSelectBasic = async function() {
+            setStatus('select-basic', 'loading', '⏳ Running basic SELECT tests...');
+            const tests = [];
+
+            // SELECT *
+            let r = await runTest("SELECT * FROM users", (res) => ({
+                pass: res.rows && res.rows.length === 6,
+                reason: `Expected 6 rows, got ${res.rows?.length}`
+            }));
+            tests.push({ sql: "SELECT * FROM users", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // SELECT specific columns
+            r = await runTest("SELECT name, age FROM users", (res) => ({
+                pass: res.columns?.length === 2,
+                reason: `Expected 2 columns, got ${res.columns?.length}`
+            }));
+            tests.push({ sql: "SELECT name, age FROM users", ...r, details: `cols: ${r.result?.columns?.join(', ')}` });
+
+            // SELECT DISTINCT
+            r = await runTest("SELECT DISTINCT age FROM users", (res) => ({
+                pass: res.rows && res.rows.length <= 6,
+                reason: 'DISTINCT should reduce duplicates'
+            }));
+            tests.push({ sql: "SELECT DISTINCT age FROM users", ...r, details: `${r.result?.rows?.length} unique ages` });
+
+            // SELECT with simple WHERE
+            r = await runTest("SELECT * FROM users WHERE id = 1", (res) => ({
+                pass: res.rows?.length === 1,
+                reason: `Expected 1 row, got ${res.rows?.length}`
+            }));
+            tests.push({ sql: "SELECT * FROM users WHERE id = 1", ...r, details: `${r.result?.rows?.length} row` });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-select-basic').innerHTML = html;
+            setStatus('select-basic', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} basic SELECT tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('select-where');
+            updateSummary();
+        };
+
+        window.testSelectWhere = async function() {
+            setStatus('select-where', 'loading', '⏳ Running WHERE operator tests...');
+            const tests = [];
+
+            // Greater than
+            let r = await runTest("SELECT * FROM users WHERE age > 30");
+            tests.push({ sql: "SELECT * FROM users WHERE age > 30", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // Less than or equal
+            r = await runTest("SELECT * FROM users WHERE age <= 28");
+            tests.push({ sql: "SELECT * FROM users WHERE age <= 28", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // Not equal
+            r = await runTest("SELECT * FROM users WHERE name != 'Alice'");
+            tests.push({ sql: "SELECT * FROM users WHERE name != 'Alice'", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // LIKE with %
+            r = await runTest("SELECT * FROM users WHERE name LIKE 'A%'");
+            tests.push({ sql: "SELECT * FROM users WHERE name LIKE 'A%'", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // LIKE with suffix
+            r = await runTest("SELECT * FROM users WHERE name LIKE '%e'");
+            tests.push({ sql: "SELECT * FROM users WHERE name LIKE '%e'", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // BETWEEN
+            r = await runTest("SELECT * FROM users WHERE age BETWEEN 25 AND 35");
+            tests.push({ sql: "SELECT * FROM users WHERE age BETWEEN 25 AND 35", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // IN
+            r = await runTest("SELECT * FROM users WHERE id IN (1, 2, 3)");
+            tests.push({ sql: "SELECT * FROM users WHERE id IN (1, 2, 3)", ...r, details: `${r.result?.rows?.length} rows` });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-select-where').innerHTML = html;
+            setStatus('select-where', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} WHERE operator tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('select-logic');
+            updateSummary();
+        };
+
+        window.testSelectLogic = async function() {
+            setStatus('select-logic', 'loading', '⏳ Running AND/OR logic tests...');
+            const tests = [];
+
+            // AND
+            let r = await runTest("SELECT * FROM users WHERE age > 25 AND age < 35");
+            tests.push({ sql: "SELECT * FROM users WHERE age > 25 AND age < 35", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // OR
+            r = await runTest("SELECT * FROM users WHERE age < 26 OR age > 40");
+            tests.push({ sql: "SELECT * FROM users WHERE age < 26 OR age > 40", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // AND with different columns
+            r = await runTest("SELECT * FROM users WHERE age >= 30 AND name != 'Frank'");
+            tests.push({ sql: "SELECT * FROM users WHERE age >= 30 AND name != 'Frank'", ...r, details: `${r.result?.rows?.length} rows` });
+
+            // Complex: AND + OR
+            r = await runTest("SELECT * FROM users WHERE age > 30 OR name = 'Bob'");
+            tests.push({ sql: "SELECT * FROM users WHERE age > 30 OR name = 'Bob'", ...r, details: `${r.result?.rows?.length} rows` });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-select-logic').innerHTML = html;
+            setStatus('select-logic', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} logic tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('update');
+            updateSummary();
+        };
+
+        window.testUpdate = async function() {
+            setStatus('update', 'loading', '⏳ Running UPDATE tests...');
+            const tests = [];
+
+            // UPDATE with WHERE
+            let r = await runTest("UPDATE users SET age = 31 WHERE name = 'Alice'");
+            tests.push({ sql: "UPDATE users SET age = 31 WHERE name = 'Alice'", ...r });
+
+            // Verify update
+            r = await runTest("SELECT age FROM users WHERE name = 'Alice'", (res) => ({
+                pass: res.rows?.[0]?.[0] === 31,
+                reason: `Expected age=31, got ${res.rows?.[0]?.[0]}`
+            }));
+            tests.push({ sql: "SELECT age FROM users WHERE name = 'Alice'", ...r, details: `age = ${r.result?.rows?.[0]?.[0]}` });
+
+            // UPDATE multiple columns
+            r = await runTest("UPDATE users SET age = 26, name = 'Bobby' WHERE id = 2");
+            tests.push({ sql: "UPDATE users SET age = 26, name = 'Bobby' WHERE id = 2", ...r });
+
+            const { html, allPassed } = renderResults(tests);
+            document.getElementById('result-update').innerHTML = html;
+            setStatus('update', allPassed ? 'success' : 'error',
+                allPassed ? `✓ All ${tests.length} UPDATE tests passed` : '✗ Some tests failed');
+            if (allPassed) enableButton('delete');
+            updateSummary();
+        };
+
+        window.testDelete = async function() {
+            setStatus('delete', 'loading', '⏳ Running DELETE tests...');
+            const tests = [];
+
+            // Count before delete
+            let r = await runTest("SELECT COUNT(*) FROM users");
+            const countBefore = r.result?.rows?.[0]?.[0] || 0;
+            tests.push({ sql: "SELECT COUNT(*) FROM users", ...r, details: `count = ${countBefore}` });
+
+            // DELETE with WHERE
+            r = await runTest("DELETE FROM users WHERE id = 6");
+            tests.push({ sql: "DELETE FROM users WHERE id = 6", ...r });
+
+            // Verify deletion
+            r = await runTest("SELECT COUNT(*) FROM users", (res) => ({
+                pass: res.rows?.[0]?.[0] === countBefore - 1,
+                reason: `Expected ${countBefore - 1} rows, got ${res.rows?.[0]?.[0]}`
+            }));
+            tests.push({ sql: "SELECT COUNT(*) FROM users (after delete)", ...r, details: `count = ${r.result?.rows?.[0]?.[0]}` });
