+  // Split args string into array for spawnSync
+  const argsArray = args ? args.match(/(?:[^\s"]+|"[^"]*")+/g) || [] : [];
+  // Remove quotes from arguments
+  const cleanArgs = argsArray.map(arg => arg.replace(/^"|"$/g, ''));
