+  const result = spawnSync(CLI_PATH, cleanArgs, {
+    encoding: 'utf-8',
+    timeout: 30000,
+    ...options,
+  });
+
+  return {
+    stdout: result.stdout || '',
+    stderr: result.stderr || '',
+    exitCode: result.status || 0,
+    // Combined output for tests that check either stream
+    output: (result.stdout || '') + (result.stderr || ''),
