+/// Helper to map Parquet types to Lance types (mirrors ingest.zig)
+fn parquetTypeToLanceType(pq_type: parquet_meta.Type) writer.DataType {
+    return switch (pq_type) {
+        .boolean => .bool,
+        .int32 => .int32,
+        .int64 => .int64,
+        .float => .float32,
+        .double => .float64,
+        .byte_array => .string,
+        .fixed_len_byte_array => .string,
+        .int96 => .int64,
+        _ => .string,
+    };
+}
